@AbapCatalog.sqlViewName: 'ZV_ORD_SUMM'
@Analytics.dataCategory: #CUBE
@AccessControl.authorizationCheck: #CHECK
define view ZC_OrderSummary
  as select from vbak
  association [0..*] to vbap as _Items
    on $projection.SalesOrder = _Items.vbeln
{
  key vbeln    as SalesOrder,
      erdat    as CreationDate,
      SUM(netwr) as TotalRevenue,  " aggregated in HANA
      vkorg    as SalesOrg,
      _Items                        " association for lazy join
}
